import { useCallback, useEffect, useState } from "react";
import type { PlaybackState } from "../types";

const initialState: PlaybackState = {
  currentTime: 0,
  duration: 0,
  bufferedEnd: 0,
  bufferedAhead: 0,
  paused: true,
  waiting: true,
  canPlay: false,
  volume: 1,
  muted: false,
  playbackRate: 1,
  readyState: 0,
  fullscreen: false,
  pictureInPicture: false
};

export function usePlaybackState(videoRef: React.RefObject<HTMLVideoElement>, onProgress?: (state: PlaybackState) => void, resetKey?: string) {
  const [state, setState] = useState<PlaybackState>(initialState);

  useEffect(() => {
    setState(initialState);
  }, [resetKey]);

  const sync = useCallback(() => {
    const video = videoRef.current;
    if (!video) return;
    const currentTime = video.currentTime || 0;
    let bufferedEnd = video.buffered.length ? video.buffered.end(video.buffered.length - 1) : 0;
    let bufferedAhead = 0;
    for (let index = 0; index < video.buffered.length; index += 1) {
      const start = video.buffered.start(index);
      const end = video.buffered.end(index);
      if (currentTime + 0.25 >= start && currentTime <= end) {
        bufferedEnd = end;
        bufferedAhead = Math.max(0, end - currentTime);
        break;
      }
    }
    setState((previous) => {
      const next = {
        ...previous,
        currentTime,
        duration: Number.isFinite(video.duration) ? video.duration : 0,
        bufferedEnd,
        bufferedAhead,
        paused: video.paused,
        canPlay: previous.canPlay || video.readyState >= HTMLMediaElement.HAVE_CURRENT_DATA,
        volume: video.volume,
        muted: video.muted,
        playbackRate: video.playbackRate,
        readyState: video.readyState,
        fullscreen: document.fullscreenElement === video.parentElement,
        pictureInPicture: document.pictureInPictureElement === video
      };
      onProgress?.(next);
      return next;
    });
  }, [onProgress, videoRef]);

  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;

    const markLoading = () => setState((previous) => ({ ...previous, waiting: true, canPlay: false }));
    const markBuffering = () => setState((previous) => ({ ...previous, waiting: true }));
    const markReady = () => {
      if (video.readyState < HTMLMediaElement.HAVE_CURRENT_DATA) return;
      setState((previous) => ({ ...previous, waiting: false, canPlay: true }));
      sync();
    };
    const events = ["loadedmetadata", "durationchange", "timeupdate", "progress", "play", "pause", "volumechange", "ratechange", "seeking", "seeked"];
    const readyEvents = ["loadeddata", "canplay", "canplaythrough", "playing", "seeked"];
    events.forEach((event) => video.addEventListener(event, sync));
    video.addEventListener("loadstart", markLoading);
    video.addEventListener("emptied", markLoading);
    video.addEventListener("waiting", markBuffering);
    video.addEventListener("seeking", markBuffering);
    readyEvents.forEach((event) => video.addEventListener(event, markReady));
    document.addEventListener("fullscreenchange", sync);
    video.addEventListener("enterpictureinpicture", sync);
    video.addEventListener("leavepictureinpicture", sync);

    return () => {
      events.forEach((event) => video.removeEventListener(event, sync));
      video.removeEventListener("loadstart", markLoading);
      video.removeEventListener("emptied", markLoading);
      video.removeEventListener("waiting", markBuffering);
      video.removeEventListener("seeking", markBuffering);
      readyEvents.forEach((event) => video.removeEventListener(event, markReady));
      document.removeEventListener("fullscreenchange", sync);
      video.removeEventListener("enterpictureinpicture", sync);
      video.removeEventListener("leavepictureinpicture", sync);
    };
  }, [sync, videoRef]);

  return { state, sync };
}
