import { useCallback, useEffect, useMemo, useRef } from "react";
import type { DiagnosticEvent, DiagnosticsConfig, DiagnosticsReport, MkvPlayerMetadata, MkvPlayerSource } from "../types";

const sensitiveKeys = ["token", "apikey", "api_key", "key", "auth", "authorization", "password"];

function redactString(value: string) {
  try {
    const url = new URL(value);
    for (const key of Array.from(url.searchParams.keys())) {
      if (sensitiveKeys.some((sensitive) => key.toLowerCase().includes(sensitive))) {
        url.searchParams.set(key, "[redacted]");
      }
    }
    return url.toString();
  } catch {
    return value.replace(/[a-f0-9]{8}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{4}-[a-f0-9]{12}/gi, "[redacted]");
  }
}

function redactValue(value: unknown): unknown {
  if (typeof value === "string") return redactString(value);
  if (Array.isArray(value)) return value.map(redactValue);
  if (!value || typeof value !== "object") return value;
  return Object.fromEntries(
    Object.entries(value).map(([key, item]) => {
      if (sensitiveKeys.some((sensitive) => key.toLowerCase().includes(sensitive))) return [key, "[redacted]"];
      return [key, redactValue(item)];
    })
  );
}

function sourceSummary(src: MkvPlayerSource): DiagnosticsReport["source"] {
  if (typeof src === "string") return { kind: "url", url: redactString(src) };
  if (src instanceof File) {
    return { kind: "file", fileName: src.name, fileSize: src.size, fileType: src.type };
  }
  return { kind: "blob", fileSize: src.size, fileType: src.type };
}

function videoSummary(video?: HTMLVideoElement | null): DiagnosticsReport["video"] {
  if (!video) {
    return {
      currentTime: 0,
      duration: 0,
      paused: true,
      readyState: 0,
      networkState: 0,
      buffered: []
    };
  }

  const buffered = Array.from({ length: video.buffered.length }, (_, index) => ({
    start: video.buffered.start(index),
    end: video.buffered.end(index)
  }));

  return {
    currentSrc: redactString(video.currentSrc),
    currentTime: video.currentTime || 0,
    duration: Number.isFinite(video.duration) ? video.duration : 0,
    paused: video.paused,
    readyState: video.readyState,
    networkState: video.networkState,
    buffered,
    error: video.error ? { code: video.error.code, message: video.error.message } : undefined
  };
}

export function useDiagnostics({
  config,
  src,
  videoRef,
  metadata,
  selectedAudioId,
  selectedSubtitleId,
  onEvent
}: {
  config?: DiagnosticsConfig;
  src: MkvPlayerSource;
  videoRef: React.RefObject<HTMLVideoElement>;
  metadata?: MkvPlayerMetadata;
  selectedAudioId?: string;
  selectedSubtitleId?: string;
  onEvent?: (event: DiagnosticEvent) => void;
}) {
  const enabled = config?.enabled ?? false;
  const maxEvents = config?.maxEvents ?? 500;
  const startedAt = useRef(Date.now());
  const nextId = useRef(1);
  const events = useRef<DiagnosticEvent[]>([]);
  const onEventRef = useRef(onEvent);

  useEffect(() => {
    onEventRef.current = onEvent;
  }, [onEvent]);

  const add = useCallback(
    (level: DiagnosticEvent["level"], category: string, message: string, data?: unknown) => {
      if (!enabled) return;
      const event: DiagnosticEvent = {
        id: nextId.current++,
        at: new Date().toISOString(),
        elapsedMs: Date.now() - startedAt.current,
        level,
        category,
        message,
        data: redactValue(data)
      };
      events.current = [...events.current.slice(-(maxEvents - 1)), event];
      onEventRef.current?.(event);
    },
    [enabled, maxEvents]
  );

  const report = useCallback((): DiagnosticsReport => {
    return {
      generatedAt: new Date().toISOString(),
      userAgent: typeof navigator === "undefined" ? undefined : navigator.userAgent,
      source: sourceSummary(src),
      video: videoSummary(videoRef.current),
      metadata: redactValue(metadata) as MkvPlayerMetadata | undefined,
      selectedAudioId,
      selectedSubtitleId,
      events: [...events.current]
    };
  }, [metadata, selectedAudioId, selectedSubtitleId, src, videoRef]);

  const download = useCallback(() => {
    const blob = new Blob([JSON.stringify(report(), null, 2)], { type: "application/json" });
    const url = URL.createObjectURL(blob);
    const anchor = document.createElement("a");
    anchor.href = url;
    anchor.download = `mkv-player-diagnostics-${new Date().toISOString().replace(/[:.]/g, "-")}.json`;
    document.body.append(anchor);
    anchor.click();
    anchor.remove();
    URL.revokeObjectURL(url);
  }, [report]);

  useEffect(() => {
    if (!enabled || !config?.exposeGlobal || typeof window === "undefined") return;
    const name = config.globalName || "__MKV_PLAYER_DIAGNOSTICS__";
    (window as unknown as Record<string, unknown>)[name] = { report };
    return () => {
      delete (window as unknown as Record<string, unknown>)[name];
    };
  }, [config?.exposeGlobal, config?.globalName, enabled, report]);

  return useMemo(() => ({ add, report, download }), [add, report, download]);
}
