import {
  Airplay,
  Captions,
  Check,
  ChevronsLeft,
  ChevronsRight,
  Expand,
  Gauge,
  Languages,
  Loader2,
  FileDown,
  Maximize,
  Minimize,
  MonitorUp,
  Move,
  Pause,
  PictureInPicture2,
  Play,
  Settings,
  Volume2,
  VolumeX,
  X
} from "lucide-react";
import Hls from "hls.js";
import { useCallback, useEffect, useMemo, useRef, useState } from "react";
import type { PointerEvent as ReactPointerEvent } from "react";
import { buildSubtitleUrl, resolvePlaybackSource } from "../core/source";
import { activeCue, loadSubtitleCues } from "../core/subtitles";
import { useDiagnostics } from "../hooks/useDiagnostics";
import { usePlaybackState } from "../hooks/usePlaybackState";
import type {
  AudioTrack,
  MkvPlayerError,
  MkvPlayerMetadata,
  MkvPlayerProps,
  PlaybackStrategy,
  PopoutConfig,
  PopoutPlacement,
  PopoutPosition,
  PopoutSize,
  PopoutState,
  SubtitleCue,
  SubtitleStyle,
  SubtitleTrack
} from "../types";

const defaultSubtitleStyle: SubtitleStyle = {
  size: 28,
  color: "#ffffff",
  backgroundOpacity: 0.45,
  position: 14,
  delay: 0
};

const speeds = [0.5, 0.75, 1, 1.25, 1.5, 2];
const popoutMargin = 18;
const popoutPeek = 72;
const defaultPopoutSize: PopoutSize = { width: 420, height: 236 };
const defaultPopoutMinSize: PopoutSize = { width: 280, height: 158 };
const hlsRevealBufferSeconds = 12;
const imageLike = /\.(avif|gif|jpe?g|png|svg|webp)(\?|#|$)/i;

function formatTime(value: number): string {
  if (!Number.isFinite(value) || value <= 0) return "0:00";
  const hours = Math.floor(value / 3600);
  const minutes = Math.floor((value % 3600) / 60);
  const seconds = Math.floor(value % 60);
  if (hours > 0) return `${hours}:${String(minutes).padStart(2, "0")}:${String(seconds).padStart(2, "0")}`;
  return `${minutes}:${String(seconds).padStart(2, "0")}`;
}

function trackLabel(track: AudioTrack | SubtitleTrack): string {
  return track.label || track.language || ("codec" in track && track.codec ? track.codec : undefined) || `Track ${"index" in track ? Number(track.index) + 1 : ""}`;
}

function normalizePopoutConfig(popout: MkvPlayerProps["popout"]): Required<PopoutConfig> {
  const config = typeof popout === "object" ? popout : {};
  return {
    enabled: popout !== false && (popout === true || config.enabled === true),
    defaultOpen: config.defaultOpen ?? false,
    initialPlacement: config.initialPlacement ?? "bottom-right",
    initialSize: config.initialSize ?? defaultPopoutSize,
    minSize: config.minSize ?? defaultPopoutMinSize,
    maxWidthRatio: config.maxWidthRatio ?? 0.7,
    persistKey: config.persistKey ?? "",
    allowOffscreenPeek: config.allowOffscreenPeek ?? true
  };
}

function placementPosition(placement: PopoutPlacement, size: PopoutSize): PopoutPosition {
  if (typeof window === "undefined") return { x: popoutMargin, y: popoutMargin };
  const right = Math.max(popoutMargin, window.innerWidth - size.width - popoutMargin);
  const bottom = Math.max(popoutMargin, window.innerHeight - size.height - popoutMargin);
  return {
    x: placement.endsWith("right") ? right : popoutMargin,
    y: placement.startsWith("bottom") ? bottom : popoutMargin
  };
}

function clampPopoutPosition(position: PopoutPosition, size: PopoutSize, allowPeek: boolean): PopoutPosition {
  if (typeof window === "undefined") return position;
  const minVisible = allowPeek ? popoutPeek : size.width;
  const minX = allowPeek ? -(size.width - minVisible) : popoutMargin;
  const minY = allowPeek ? -(size.height - minVisible) : popoutMargin;
  const maxX = allowPeek ? window.innerWidth - minVisible : window.innerWidth - size.width - popoutMargin;
  const maxY = allowPeek ? window.innerHeight - minVisible : window.innerHeight - size.height - popoutMargin;
  return {
    x: Math.min(Math.max(position.x, minX), Math.max(minX, maxX)),
    y: Math.min(Math.max(position.y, minY), Math.max(minY, maxY))
  };
}

function clampPopoutSize(size: PopoutSize, minSize: PopoutSize, maxWidthRatio: number): PopoutSize {
  if (typeof window === "undefined") return size;
  const maxWidth = Math.max(minSize.width, Math.floor(window.innerWidth * maxWidthRatio));
  const maxHeight = Math.max(minSize.height, window.innerHeight - popoutMargin * 2);
  const width = Math.min(Math.max(size.width, minSize.width), maxWidth);
  const height = Math.min(Math.max(size.height, minSize.height), maxHeight);
  return { width, height };
}

function nearestPlacement(position: PopoutPosition, size: PopoutSize): PopoutPlacement {
  if (typeof window === "undefined") return "bottom-right";
  const vertical = position.y + size.height / 2 > window.innerHeight / 2 ? "bottom" : "top";
  const horizontal = position.x + size.width / 2 > window.innerWidth / 2 ? "right" : "left";
  return `${vertical}-${horizontal}` as PopoutPlacement;
}

function isTucked(position: PopoutPosition, size: PopoutSize) {
  if (typeof window === "undefined") return false;
  return position.x < 0 || position.y < 0 || position.x + size.width > window.innerWidth || position.y + size.height > window.innerHeight;
}

function IconButton({
  label,
  children,
  onClick,
  active,
  disabled
}: {
  label: string;
  children: React.ReactNode;
  onClick?: () => void;
  active?: boolean;
  disabled?: boolean;
}) {
  return (
    <button className="mkv-icon-button" type="button" aria-label={label} title={label} onClick={onClick} data-active={active} disabled={disabled}>
      {children}
    </button>
  );
}

function Panel({ children }: { children: React.ReactNode }) {
  return <div className="mkv-panel">{children}</div>;
}

export function MkvPlayer({
  src,
  title,
  poster,
  loadingPreview,
  autoPlay,
  muted,
  server,
  subtitles = [],
  className,
  storageKey,
  popout,
  diagnostics,
  onDiagnosticsEvent,
  onPopoutChange,
  startAt = null,
  onReady,
  onError,
  onProgress,
  onEnded
}: MkvPlayerProps) {
  const videoRef = useRef<HTMLVideoElement>(null);
  const shellRef = useRef<HTMLDivElement>(null);
  const hlsRef = useRef<Hls>();
  const hideTimer = useRef<number>();
  const previousPopoutSize = useRef<PopoutSize>();
  const [videoUrl, setVideoUrl] = useState("");
  const { state } = usePlaybackState(videoRef, onProgress, videoUrl);
  const [objectUrl, setObjectUrl] = useState<string>();
  const [metadata, setMetadata] = useState<MkvPlayerMetadata>({
    title,
    audioTracks: [],
    subtitleTracks: subtitles,
    chapters: [],
    strategy: "native"
  });
  const [selectedAudioId, setSelectedAudioId] = useState<string>();
  const [selectedSubtitleId, setSelectedSubtitleId] = useState<string | "off">("off");
  const [subtitleCues, setSubtitleCues] = useState<SubtitleCue[]>([]);
  const [subtitleStyle, setSubtitleStyle] = useState<SubtitleStyle>(defaultSubtitleStyle);
  const [controlsVisible, setControlsVisible] = useState(true);
  const [menu, setMenu] = useState<"audio" | "subtitles" | "settings" | null>(null);
  const [error, setError] = useState<MkvPlayerError>();
  const [subtitleWarning, setSubtitleWarning] = useState<string>();
  const [resolvingSource, setResolvingSource] = useState(false);
  const [mediaRevealed, setMediaRevealed] = useState(false);
  const onReadyRef = useRef(onReady);
  const onErrorRef = useRef(onError);
  const onEndedRef = useRef(onEnded);
  const onPopoutChangeRef = useRef(onPopoutChange);
  const popoutConfig = useMemo(() => normalizePopoutConfig(popout), [popout]);
  const [popoutState, setPopoutState] = useState<PopoutState>(() => {
    const size = typeof window === "undefined" ? popoutConfig.initialSize : clampPopoutSize(popoutConfig.initialSize, popoutConfig.minSize, popoutConfig.maxWidthRatio);
    const fallback: PopoutState = {
      open: popoutConfig.defaultOpen,
      position: placementPosition(popoutConfig.initialPlacement, size),
      size,
      dockedPlacement: popoutConfig.initialPlacement,
      minimized: false
    };
    if (!popoutConfig.persistKey || typeof window === "undefined") return fallback;
    try {
      const saved = JSON.parse(localStorage.getItem(`${popoutConfig.persistKey}:popout`) ?? "null") as Partial<PopoutState> | null;
      if (!saved) return fallback;
      const nextSize = clampPopoutSize(saved.size ?? size, popoutConfig.minSize, popoutConfig.maxWidthRatio);
      return {
        open: saved.open ?? fallback.open,
        position: clampPopoutPosition(saved.position ?? fallback.position, nextSize, popoutConfig.allowOffscreenPeek),
        size: nextSize,
        dockedPlacement: saved.dockedPlacement ?? fallback.dockedPlacement,
        minimized: saved.minimized ?? false
      };
    } catch {
      return fallback;
    }
  });

  useEffect(() => {
    onReadyRef.current = onReady;
    onErrorRef.current = onError;
    onEndedRef.current = onEnded;
    onPopoutChangeRef.current = onPopoutChange;
  }, [onEnded, onError, onPopoutChange, onReady]);

  const selectedSubtitle = useMemo(
    () => metadata.subtitleTracks.find((track) => track.id === selectedSubtitleId),
    [metadata.subtitleTracks, selectedSubtitleId]
  );
  const subtitlesSignature = useMemo(() => JSON.stringify(subtitles), [subtitles]);
  const serverSignature = useMemo(() => JSON.stringify(server), [server]);
  const cue = activeCue(subtitleCues, state.currentTime, subtitleStyle.delay);
  const displayDuration = metadata.duration || state.duration;
  const progress = displayDuration ? (state.currentTime / displayDuration) * 100 : 0;
  const buffered = displayDuration ? (state.bufferedEnd / displayDuration) * 100 : 0;
  const { add: addDiagnostic, download: downloadDiagnostics } = useDiagnostics({
    config: diagnostics,
    src,
    videoRef,
    metadata,
    selectedAudioId,
    selectedSubtitleId,
    onEvent: onDiagnosticsEvent
  });
  const popoutOpen = popoutConfig.enabled && popoutState.open;
  const popoutTucked = popoutOpen && isTucked(popoutState.position, popoutState.size);
  const hlsInitialBufferReady =
    metadata.strategy !== "server-hls" ||
    state.bufferedAhead >= Math.min(hlsRevealBufferSeconds, Math.max(3, (displayDuration || hlsRevealBufferSeconds) - state.currentTime));
  const mediaPlayable = !resolvingSource && !error && mediaRevealed;
  const showInitialPreview = !mediaRevealed && !error && Boolean(loadingPreview);
  const loadingPreviewIsImage = Boolean(loadingPreview && (loadingPreview.type === "image" || imageLike.test(loadingPreview.src)));
  const showBufferingSpinner = mediaPlayable && state.waiting && !state.paused;
  const chromeVisible = mediaPlayable && (controlsVisible || state.paused);
  const popoutStyle = popoutOpen
    ? {
        left: `${popoutState.position.x}px`,
        top: `${popoutState.position.y}px`,
        width: `${popoutState.size.width}px`,
        height: `${popoutState.minimized ? 52 : popoutState.size.height}px`
      }
    : undefined;

  useEffect(() => {
    onPopoutChangeRef.current?.(popoutState);
    if (!popoutConfig.persistKey || typeof window === "undefined") return;
    localStorage.setItem(`${popoutConfig.persistKey}:popout`, JSON.stringify(popoutState));
  }, [popoutConfig.persistKey, popoutState]);

  useEffect(() => {
    if (!popoutConfig.enabled && popoutState.open) setPopoutState((current) => ({ ...current, open: false, minimized: false }));
  }, [popoutConfig.enabled, popoutState.open]);

  useEffect(() => {
    if (!resolvingSource && !error && state.canPlay && hlsInitialBufferReady) setMediaRevealed(true);
  }, [error, hlsInitialBufferReady, resolvingSource, state.canPlay]);

  useEffect(() => {
    const onResize = () => {
      setPopoutState((current) => {
        const size = clampPopoutSize(current.size, popoutConfig.minSize, popoutConfig.maxWidthRatio);
        return {
          ...current,
          size,
          position: clampPopoutPosition(current.position, size, popoutConfig.allowOffscreenPeek)
        };
      });
    };
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, [popoutConfig.allowOffscreenPeek, popoutConfig.maxWidthRatio, popoutConfig.minSize]);

  const reportError = useCallback(
    (next: MkvPlayerError) => {
      setError(next);
      addDiagnostic("error", "player", next.code, { message: next.message, cause: String(next.cause ?? "") });
      onErrorRef.current?.(next);
    },
    [addDiagnostic]
  );

  const reportSubtitleWarning = useCallback(
    (message: string, cause?: unknown) => {
      setSubtitleWarning(message);
      setSubtitleCues([]);
      setSelectedSubtitleId("off");
      addDiagnostic("warn", "subtitles", message, { cause: String(cause ?? "") });
      window.setTimeout(() => setSubtitleWarning(undefined), 5200);
    },
    [addDiagnostic]
  );

  const previousObjectUrl = useRef<string>();

  useEffect(() => {
    let cancelled = false;
    setError(undefined);
    setSubtitleWarning(undefined);
    setResolvingSource(true);
    setMediaRevealed(false);
    setVideoUrl("");
    setSubtitleCues([]);
    setSelectedSubtitleId("off");
    setMetadata({
      title,
      audioTracks: [],
      subtitleTracks: subtitles,
      chapters: [],
      strategy: "native"
    });
    addDiagnostic("info", "source", "Resolving playback source", { serverEnabled: server?.enabled, delivery: server?.delivery });
    resolvePlaybackSource(src, server)
      .then((resolved) => {
        if (cancelled) return;
        if (previousObjectUrl.current) URL.revokeObjectURL(previousObjectUrl.current);
        previousObjectUrl.current = resolved.objectUrl;
        setVideoUrl(resolved.videoUrl);
        setObjectUrl(resolved.objectUrl);
        const nextMetadata: MkvPlayerMetadata = {
          title,
          duration: resolved.metadata?.duration,
          videoCodec: resolved.metadata?.videoCodec,
          audioTracks: resolved.metadata?.audioTracks ?? [],
          subtitleTracks: [...(resolved.metadata?.subtitleTracks ?? []), ...subtitles],
          chapters: resolved.metadata?.chapters ?? [],
          strategy: resolved.strategy
        };
        setMetadata(nextMetadata);
        setSelectedAudioId(nextMetadata.audioTracks.find((track) => track.default)?.id ?? nextMetadata.audioTracks[0]?.id);
        setSelectedSubtitleId(nextMetadata.subtitleTracks.find((track) => track.default && track.src)?.id ?? "off");
        addDiagnostic("info", "source", "Playback source ready", {
          strategy: resolved.strategy,
          videoUrl: resolved.videoUrl,
          audioTracks: nextMetadata.audioTracks.length,
          subtitleTracks: nextMetadata.subtitleTracks.length,
          duration: nextMetadata.duration
        });
        setResolvingSource(false);
        onReadyRef.current?.(nextMetadata);
      })
      .catch((cause) => {
        setResolvingSource(false);
        reportError({ code: "SOURCE_RESOLUTION_FAILED", message: "Could not prepare this media source.", cause });
      });

    return () => {
      cancelled = true;
    };
  }, [addDiagnostic, reportError, serverSignature, src, subtitlesSignature, title]);

  useEffect(() => {
    return () => {
      if (objectUrl) URL.revokeObjectURL(objectUrl);
    };
  }, [objectUrl]);

  useEffect(() => {
    const video = videoRef.current;
    if (!video || !videoUrl || metadata.strategy !== "server-hls") return;

    hlsRef.current?.destroy();
    hlsRef.current = undefined;

    if (Hls.isSupported()) {
      const hls = new Hls({
        backBufferLength: 90,
        maxBufferLength: 90,
        maxMaxBufferLength: 180,
        fragLoadPolicy: {
          default: {
            maxTimeToFirstByteMs: 60000,
            maxLoadTimeMs: 180000,
            timeoutRetry: {
              maxNumRetry: 1,
              retryDelayMs: 1000,
              maxRetryDelayMs: 1000
            },
            errorRetry: {
              maxNumRetry: 2,
              retryDelayMs: 1000,
              maxRetryDelayMs: 4000
            }
          }
        }
      });
      hlsRef.current = hls;
      hls.on(Hls.Events.MEDIA_ATTACHED, () => hls.loadSource(videoUrl));
      hls.on(Hls.Events.MANIFEST_PARSED, (_, data) => {
        addDiagnostic("info", "hls", "HLS manifest ready", { levels: data.levels.length, duration: metadata.duration });
      });
      hls.on(Hls.Events.ERROR, (_, data) => {
        addDiagnostic(data.fatal ? "error" : "warn", "hls", data.details, {
          fatal: data.fatal,
          type: data.type,
          fragment: data.frag ? { sn: data.frag.sn, start: data.frag.start, duration: data.frag.duration } : undefined
        });
        if (data.fatal) {
          if (data.type === Hls.ErrorTypes.NETWORK_ERROR) hls.startLoad();
          else if (data.type === Hls.ErrorTypes.MEDIA_ERROR) hls.recoverMediaError();
          else reportError({ code: "HLS_FATAL_ERROR", message: "The segmented stream could not be played.", cause: data.details });
        }
      });
      hls.attachMedia(video);
      return () => {
        hls.destroy();
        if (hlsRef.current === hls) hlsRef.current = undefined;
      };
    }

    if (video.canPlayType("application/vnd.apple.mpegurl")) {
      video.src = videoUrl;
      return;
    }

    reportError({ code: "HLS_NOT_SUPPORTED", message: "This browser cannot play HLS streams." });
  }, [addDiagnostic, metadata.duration, metadata.strategy, reportError, videoUrl]);

  useEffect(() => {
    if (!selectedSubtitle || selectedSubtitleId === "off") {
      setSubtitleCues([]);
      return;
    }
    const url = buildSubtitleUrl(server, src, selectedSubtitle);
    if (!url) {
      setSubtitleCues([]);
      addDiagnostic("warn", "subtitles", "No subtitle URL available", { subtitle: selectedSubtitle });
      return;
    }
    let cancelled = false;
    addDiagnostic("info", "subtitles", "Loading subtitle track", { id: selectedSubtitle.id, url });
    loadSubtitleCues(url)
      .then((cues) => {
        if (!cancelled) {
          setSubtitleCues(cues);
          addDiagnostic("info", "subtitles", "Subtitle track loaded", { id: selectedSubtitle.id, cues: cues.length });
        }
      })
      .catch((cause) => {
        if (!cancelled) reportSubtitleWarning("Could not load the selected subtitles.", cause);
      });
    return () => {
      cancelled = true;
    };
  }, [addDiagnostic, reportSubtitleWarning, selectedSubtitle, selectedSubtitleId, serverSignature, src]);

  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;
    const eventNames = ["loadstart", "loadedmetadata", "canplay", "playing", "waiting", "seeking", "seeked", "stalled", "suspend", "ended", "error"];
    const logMediaEvent = (event: Event) => {
      addDiagnostic(event.type === "error" ? "error" : event.type === "waiting" || event.type === "stalled" ? "warn" : "debug", "media", event.type, {
        currentTime: video.currentTime,
        duration: Number.isFinite(video.duration) ? video.duration : undefined,
        readyState: video.readyState,
        networkState: video.networkState,
        bufferedEnd: video.buffered.length ? video.buffered.end(video.buffered.length - 1) : 0,
        error: video.error ? { code: video.error.code, message: video.error.message } : undefined
      });
    };
    eventNames.forEach((eventName) => video.addEventListener(eventName, logMediaEvent));
    return () => eventNames.forEach((eventName) => video.removeEventListener(eventName, logMediaEvent));
  }, [addDiagnostic, videoUrl]);

  useEffect(() => {
    const video = videoRef.current;
    if (!video || !storageKey) return;
    const saved = startAt && startAt > 0 ? startAt : Number(localStorage.getItem(`${storageKey}:time`) ?? 0);
    if (saved > 0) video.currentTime = saved;
    const interval = window.setInterval(() => {
      if (video.currentTime > 5 && !video.ended) localStorage.setItem(`${storageKey}:time`, String(video.currentTime));
    }, 2000);
    return () => window.clearInterval(interval);
  }, [startAt, storageKey, videoUrl]);

  useEffect(() => {
    const video = videoRef.current;
    if (!video) return;
    const handleEnded = () => onEndedRef.current?.();
    video.addEventListener("ended", handleEnded);
    return () => video.removeEventListener("ended", handleEnded);
  }, [videoUrl]);

  const showControls = useCallback(() => {
    setControlsVisible(true);
    window.clearTimeout(hideTimer.current);
    hideTimer.current = window.setTimeout(() => {
      if (!videoRef.current?.paused) setControlsVisible(false);
    }, 2600);
  }, []);

  const togglePlay = useCallback(() => {
    const video = videoRef.current;
    if (!video || !state.canPlay) return;
    if (video.paused) void video.play();
    else video.pause();
  }, [state.canPlay]);

  const seekBy = useCallback((seconds: number) => {
    const video = videoRef.current;
    if (!video || !state.canPlay) return;
    video.currentTime = Math.min(Math.max(0, video.currentTime + seconds), displayDuration || Number.MAX_SAFE_INTEGER);
  }, [displayDuration, state.canPlay]);

  const setTimeFromRange = (value: string) => {
    const video = videoRef.current;
    if (!video || !displayDuration || !state.canPlay) return;
    video.currentTime = (Number(value) / 1000) * displayDuration;
  };

  const toggleFullscreen = () => {
    const shell = shellRef.current;
    if (!shell) return;
    if (document.fullscreenElement) void document.exitFullscreen();
    else void shell.requestFullscreen();
  };

  const togglePiP = async () => {
    const video = videoRef.current;
    if (!video || !document.pictureInPictureEnabled) return;
    if (document.pictureInPictureElement) await document.exitPictureInPicture();
    else await video.requestPictureInPicture();
  };

  const openPopout = useCallback(() => {
    if (!popoutConfig.enabled) return;
    setMenu(null);
    setPopoutState((current) => {
      const size = clampPopoutSize(current.size, popoutConfig.minSize, popoutConfig.maxWidthRatio);
      const placement = current.dockedPlacement ?? popoutConfig.initialPlacement;
      return {
        ...current,
        open: true,
        minimized: false,
        size,
        dockedPlacement: placement,
        position: clampPopoutPosition(current.position ?? placementPosition(placement, size), size, popoutConfig.allowOffscreenPeek)
      };
    });
  }, [popoutConfig.allowOffscreenPeek, popoutConfig.enabled, popoutConfig.initialPlacement, popoutConfig.maxWidthRatio, popoutConfig.minSize]);

  const closePopout = useCallback(() => {
    setMenu(null);
    setPopoutState((current) => ({ ...current, open: false, minimized: false }));
  }, []);

  const tuckPopout = useCallback(() => {
    setMenu(null);
    setPopoutState((current) => {
      const placement = nearestPlacement(current.position, current.size);
      const x = placement.endsWith("right") ? window.innerWidth - popoutPeek : -(current.size.width - popoutPeek);
      const y = Math.min(Math.max(current.position.y, popoutMargin), window.innerHeight - popoutPeek);
      return { ...current, position: { x, y }, dockedPlacement: placement, minimized: false };
    });
  }, []);

  const restoreTuckedPopout = useCallback(() => {
    setPopoutState((current) => {
      const placement = nearestPlacement(current.position, current.size);
      return {
        ...current,
        minimized: false,
        dockedPlacement: placement,
        position: placementPosition(placement, current.size)
      };
    });
  }, []);

  const togglePopoutMinimized = useCallback(() => {
    setMenu(null);
    setPopoutState((current) => ({ ...current, minimized: !current.minimized }));
  }, []);

  const toggleCompactPopoutSize = useCallback(() => {
    if (!popoutOpen || typeof window === "undefined" || window.innerWidth <= 760) return;
    setPopoutState((current) => {
      const compact = clampPopoutSize(popoutConfig.initialSize, popoutConfig.minSize, popoutConfig.maxWidthRatio);
      const isCompact = Math.abs(current.size.width - compact.width) < 8 && Math.abs(current.size.height - compact.height) < 8;
      const nextSize = isCompact && previousPopoutSize.current ? previousPopoutSize.current : compact;
      previousPopoutSize.current = current.size;
      return {
        ...current,
        size: nextSize,
        minimized: false,
        position: clampPopoutPosition(current.position, nextSize, popoutConfig.allowOffscreenPeek)
      };
    });
  }, [popoutConfig.allowOffscreenPeek, popoutConfig.initialSize, popoutConfig.maxWidthRatio, popoutConfig.minSize, popoutOpen]);

  const startPopoutDrag = useCallback(
    (event: ReactPointerEvent<HTMLElement>) => {
      if (!popoutOpen || event.button !== 0 || typeof window === "undefined" || window.innerWidth <= 760) return;
      const target = event.target as HTMLElement;
      if (target.closest("button,input,select,.mkv-controls,.mkv-menu-wrap")) return;
      event.preventDefault();
      const start = {
        pointerX: event.clientX,
        pointerY: event.clientY,
        position: popoutState.position,
        size: popoutState.size
      };
      event.currentTarget.setPointerCapture(event.pointerId);
      const onMove = (moveEvent: PointerEvent) => {
        const nextPosition = clampPopoutPosition(
          {
            x: start.position.x + moveEvent.clientX - start.pointerX,
            y: start.position.y + moveEvent.clientY - start.pointerY
          },
          start.size,
          popoutConfig.allowOffscreenPeek
        );
        setPopoutState((current) => ({ ...current, position: nextPosition, minimized: false }));
      };
      const onUp = () => {
        window.removeEventListener("pointermove", onMove);
        window.removeEventListener("pointerup", onUp);
        setPopoutState((current) => {
          const placement = nearestPlacement(current.position, current.size);
          const nearEdge =
            current.position.x <= popoutMargin * 2 ||
            current.position.y <= popoutMargin * 2 ||
            window.innerWidth - (current.position.x + current.size.width) <= popoutMargin * 2 ||
            window.innerHeight - (current.position.y + current.size.height) <= popoutMargin * 2;
          return {
            ...current,
            dockedPlacement: placement,
            position: nearEdge ? placementPosition(placement, current.size) : clampPopoutPosition(current.position, current.size, popoutConfig.allowOffscreenPeek)
          };
        });
      };
      window.addEventListener("pointermove", onMove);
      window.addEventListener("pointerup", onUp, { once: true });
    },
    [popoutConfig.allowOffscreenPeek, popoutOpen, popoutState.position, popoutState.size]
  );

  const startPopoutResize = useCallback(
    (event: ReactPointerEvent<HTMLButtonElement>, corner: "se" | "sw" | "ne" | "nw") => {
      if (!popoutOpen || event.button !== 0 || typeof window === "undefined" || window.innerWidth <= 760) return;
      event.preventDefault();
      event.stopPropagation();
      const start = {
        pointerX: event.clientX,
        pointerY: event.clientY,
        position: popoutState.position,
        size: popoutState.size
      };
      event.currentTarget.setPointerCapture(event.pointerId);
      const onMove = (moveEvent: PointerEvent) => {
        const deltaX = moveEvent.clientX - start.pointerX;
        const deltaY = moveEvent.clientY - start.pointerY;
        const widthDelta = corner.endsWith("e") ? deltaX : -deltaX;
        const rawWidth = start.size.width + widthDelta;
        const rawHeight = Math.round(rawWidth * 9 / 16);
        const nextSize = clampPopoutSize({ width: rawWidth, height: rawHeight }, popoutConfig.minSize, popoutConfig.maxWidthRatio);
        const nextPosition = {
          x: corner.endsWith("w") ? start.position.x + (start.size.width - nextSize.width) : start.position.x,
          y: corner.startsWith("n") ? start.position.y + (start.size.height - nextSize.height) : start.position.y
        };
        setPopoutState((current) => ({
          ...current,
          size: nextSize,
          minimized: false,
          position: clampPopoutPosition(nextPosition, nextSize, popoutConfig.allowOffscreenPeek)
        }));
      };
      const onUp = () => {
        window.removeEventListener("pointermove", onMove);
        window.removeEventListener("pointerup", onUp);
      };
      window.addEventListener("pointermove", onMove);
      window.addEventListener("pointerup", onUp, { once: true });
    },
    [popoutConfig.allowOffscreenPeek, popoutConfig.maxWidthRatio, popoutConfig.minSize, popoutOpen, popoutState.position, popoutState.size]
  );

  const selectAudio = (track: AudioTrack) => {
    setSelectedAudioId(track.id);
    addDiagnostic("info", "audio", "Selecting audio track", track);
    const video = videoRef.current as HTMLVideoElement & { audioTracks?: { enabled: boolean; id?: string; language?: string; label?: string }[] };
    if (video?.audioTracks) {
      Array.from(video.audioTracks).forEach((nativeTrack, index) => {
        nativeTrack.enabled = nativeTrack.id === track.id || index === track.index;
      });
    }
    if (server?.enabled && typeof src === "string" && video) {
      const nextUrl = new URL(server.delivery === "hls" ? "/hls/session" : "/stream", server.baseUrl);
      nextUrl.searchParams.set("url", new URL(src, window.location.href).toString());
      if (server.delivery !== "hls") {
        nextUrl.searchParams.set("mode", "auto");
        if (server.delivery) nextUrl.searchParams.set("delivery", server.delivery);
      }
      nextUrl.searchParams.set("audioTrack", String(track.index));
      const currentTime = video.currentTime;
      const wasPaused = video.paused;
      if (server.delivery === "hls") {
        fetch(nextUrl)
          .then((response) => {
            if (!response.ok) throw new Error(`HLS audio session failed with ${response.status}`);
            return response.json() as Promise<{ playlistUrl: string }>;
          })
          .then((payload) => {
            setVideoUrl(new URL(payload.playlistUrl, server.baseUrl).toString());
            window.setTimeout(() => {
              if (!videoRef.current) return;
              videoRef.current.currentTime = currentTime;
              if (!wasPaused) void videoRef.current.play();
            }, 900);
          })
          .catch((cause) => reportError({ code: "AUDIO_SWITCH_FAILED", message: "Could not switch audio tracks.", cause }));
      } else {
        nextUrl.searchParams.set("subtitleTrack", "off");
        setVideoUrl(nextUrl.toString());
        window.setTimeout(() => {
          if (!videoRef.current) return;
          videoRef.current.currentTime = currentTime;
          if (!wasPaused) void videoRef.current.play();
        }, 600);
      }
    }
  };

  useEffect(() => {
    const onKeyDown = (event: KeyboardEvent) => {
      const target = event.target as HTMLElement | null;
      if (target?.tagName === "INPUT" || target?.tagName === "TEXTAREA" || target?.isContentEditable) return;
      if (event.key === "Escape") {
        if (menu) setMenu(null);
        else if (popoutOpen) closePopout();
      }
      if (event.key === " ") {
        event.preventDefault();
        togglePlay();
      }
      if (event.key === "ArrowLeft") seekBy(-10);
      if (event.key === "ArrowRight") seekBy(10);
      if (event.key.toLowerCase() === "f") toggleFullscreen();
      if (event.key.toLowerCase() === "m" && videoRef.current) videoRef.current.muted = !videoRef.current.muted;
    };
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [closePopout, menu, popoutOpen, seekBy, togglePlay]);

  const strategyLabel: Record<PlaybackStrategy, string> = {
    native: "Native",
    "server-remux": "Server remux",
    "server-transcode": "Server transcode",
    "server-hls": "Seekable HLS",
    unsupported: "Unsupported"
  };

  return (
    <>
    {popoutOpen ? <div className="mkv-popout-placeholder" aria-hidden="true" /> : null}
    <div
      ref={shellRef}
      className={`mkv-player ${popoutOpen ? "mkv-popout-open" : ""} ${popoutState.minimized ? "mkv-popout-minimized" : ""} ${popoutTucked ? "mkv-popout-tucked" : ""} ${className ?? ""}`}
      style={popoutStyle}
      data-popout={popoutOpen}
      data-minimized={popoutOpen && popoutState.minimized}
      data-loading={!mediaPlayable && !error}
      onMouseMove={showControls}
      onTouchStart={showControls}
      onPointerDown={startPopoutDrag}
      onDoubleClick={(event) => {
        if (popoutOpen && (event.target as HTMLElement).closest(".mkv-topbar")) toggleCompactPopoutSize();
      }}
    >
      {popoutOpen ? (
        <div className="mkv-popout-header">
          <span className="mkv-popout-grip"><Move size={14} /> Floating</span>
          <div className="mkv-popout-actions">
            <IconButton label={popoutState.minimized ? "Restore floating player" : "Minimize floating player"} onClick={togglePopoutMinimized}>
              <Minimize />
            </IconButton>
            <IconButton label="Tuck floating player" onClick={tuckPopout}>
              <Move />
            </IconButton>
            <IconButton label="Close floating player" onClick={closePopout}>
              <X />
            </IconButton>
          </div>
        </div>
      ) : null}

      {popoutTucked ? <button className="mkv-popout-peek" type="button" aria-label="Restore tucked player" onClick={restoreTuckedPopout} /> : null}

      <video
        ref={videoRef}
        className={`mkv-video ${mediaPlayable ? "" : "mkv-video-pending"}`}
        src={metadata.strategy === "server-hls" && Hls.isSupported() ? undefined : videoUrl || undefined}
        poster={poster}
        autoPlay={autoPlay}
        muted={muted}
        playsInline
        controls={false}
        onClick={mediaPlayable ? togglePlay : undefined}
        onDoubleClick={mediaPlayable ? toggleFullscreen : undefined}
        onError={() => {
          if (videoUrl) reportError({ code: "MEDIA_ERROR", message: "This file could not be played by the current browser or stream helper." });
        }}
      />

      {showInitialPreview && loadingPreview ? (
        loadingPreviewIsImage ? (
          <div className="mkv-loading-preview-wrap" aria-hidden="true">
            <img className="mkv-loading-preview" src={loadingPreview.src} alt="" />
            <Loader2 className="mkv-preview-loader mkv-spin" size={36} />
          </div>
        ) : (
          <video
            className="mkv-loading-preview"
            src={loadingPreview.src}
            poster={loadingPreview.poster}
            autoPlay
            muted
            loop
            playsInline
            aria-hidden="true"
          />
        )
      ) : null}

      {mediaPlayable ? (
        <>
          <div className="mkv-hit mkv-hit-left" onDoubleClick={() => seekBy(-10)} />
          <div className="mkv-hit mkv-hit-right" onDoubleClick={() => seekBy(10)} />
        </>
      ) : null}

      {!mediaPlayable && !error && !loadingPreview ? (
        <div className="mkv-center mkv-loading">
          <Loader2 className="mkv-spin" size={44} />
          <strong>{resolvingSource ? "Preparing video" : "Loading video"}</strong>
          <span>Controls will appear when playback is ready.</span>
        </div>
      ) : null}

      {showBufferingSpinner ? (
        <div className="mkv-center mkv-buffering" aria-label="Buffering">
          <Loader2 className="mkv-spin" size={34} />
        </div>
      ) : null}

      {mediaPlayable && state.paused ? (
        <button className="mkv-big-play" type="button" aria-label="Play" onClick={togglePlay}>
          <Play fill="currentColor" size={42} />
        </button>
      ) : null}

      {cue ? (
        <div
          className="mkv-subtitles"
          style={{
            bottom: `${subtitleStyle.position}%`,
            fontSize: `${subtitleStyle.size}px`,
            color: subtitleStyle.color
          }}
        >
          <span style={{ backgroundColor: `rgba(0, 0, 0, ${subtitleStyle.backgroundOpacity})` }}>{cue.text}</span>
        </div>
      ) : null}

      {error ? (
        <div className="mkv-error">
          <Expand size={38} />
          <strong>{error.message}</strong>
          <span>{server?.enabled ? "Try another audio/subtitle track or a transcoded stream." : "Enable the FFmpeg helper for broader MKV support."}</span>
        </div>
      ) : null}

      {subtitleWarning && !error ? (
        <div className="mkv-toast" role="status">
          {subtitleWarning}
        </div>
      ) : null}

      <div className="mkv-topbar" data-visible={chromeVisible}>
        <div>
          <strong>{title ?? metadata.title ?? "Untitled video"}</strong>
          <span>{metadata.videoCodec ? `${metadata.videoCodec} · ` : ""}{strategyLabel[metadata.strategy]}</span>
        </div>
      </div>

      <div className="mkv-controls" data-visible={chromeVisible}>
        <div className="mkv-timeline">
          <div className="mkv-buffer" style={{ width: `${Math.min(100, buffered)}%` }} />
          <div className="mkv-progress" style={{ width: `${Math.min(100, progress)}%` }} />
          {metadata.chapters.map((chapter) => (
            <span
              className="mkv-chapter"
              key={chapter.id}
              title={chapter.title}
              style={{ left: `${displayDuration ? (chapter.start / displayDuration) * 100 : 0}%` }}
            />
          ))}
          <input aria-label="Seek" min={0} max={1000} value={displayDuration ? Math.round((state.currentTime / displayDuration) * 1000) : 0} type="range" onChange={(event) => setTimeFromRange(event.target.value)} />
        </div>

        <div className="mkv-control-row">
          <div className="mkv-cluster">
            <IconButton label={state.paused ? "Play" : "Pause"} onClick={togglePlay}>
              {state.paused ? <Play fill="currentColor" /> : <Pause fill="currentColor" />}
            </IconButton>
            <IconButton label="Rewind 10 seconds" onClick={() => seekBy(-10)}>
              <ChevronsLeft />
            </IconButton>
            <IconButton label="Forward 10 seconds" onClick={() => seekBy(10)}>
              <ChevronsRight />
            </IconButton>
            <span className="mkv-time">{formatTime(state.currentTime)} / {formatTime(displayDuration || 0)}</span>
          </div>

          <div className="mkv-cluster mkv-main-actions">
            <IconButton label={state.muted ? "Unmute" : "Mute"} onClick={() => { if (videoRef.current) videoRef.current.muted = !videoRef.current.muted; }}>
              {state.muted || state.volume === 0 ? <VolumeX /> : <Volume2 />}
            </IconButton>
            <input className="mkv-volume" aria-label="Volume" type="range" min={0} max={1} step={0.01} value={state.muted ? 0 : state.volume} onChange={(event) => { if (videoRef.current) { videoRef.current.volume = Number(event.target.value); videoRef.current.muted = Number(event.target.value) === 0; } }} />
            <IconButton label="Audio tracks" active={menu === "audio"} onClick={() => setMenu(menu === "audio" ? null : "audio")}>
              <Languages />
            </IconButton>
            <IconButton label="Subtitles" active={menu === "subtitles"} onClick={() => setMenu(menu === "subtitles" ? null : "subtitles")}>
              <Captions />
            </IconButton>
            <IconButton label="Settings" active={menu === "settings"} onClick={() => setMenu(menu === "settings" ? null : "settings")}>
              <Settings />
            </IconButton>
            {popoutConfig.enabled ? (
              <IconButton label={popoutOpen ? "Restore inline player" : "Pop out player"} active={popoutOpen} onClick={popoutOpen ? closePopout : openPopout}>
                <Move />
              </IconButton>
            ) : null}
            <IconButton label="Picture in picture" onClick={togglePiP} disabled={typeof document === "undefined" || !document.pictureInPictureEnabled}>
              <PictureInPicture2 />
            </IconButton>
            <IconButton label="AirPlay" disabled={typeof window === "undefined" || !("WebKitPlaybackTargetAvailabilityEvent" in window)}>
              <Airplay />
            </IconButton>
            <IconButton label="Fullscreen" onClick={toggleFullscreen}>
              {document.fullscreenElement ? <Minimize /> : <Maximize />}
            </IconButton>
          </div>
        </div>

        {menu ? (
          <div className="mkv-menu-wrap">
            {menu === "audio" ? (
              <Panel>
                <h3><MonitorUp size={16} /> Audio</h3>
                {metadata.audioTracks.length ? metadata.audioTracks.map((track) => (
                  <button key={track.id} className="mkv-menu-item" type="button" onClick={() => selectAudio(track)}>
                    <span>{trackLabel(track)}<small>{[track.codec, track.channels, track.default ? "Default" : ""].filter(Boolean).join(" · ")}</small></span>
                    {selectedAudioId === track.id ? <Check size={18} /> : null}
                  </button>
                )) : <p className="mkv-empty">No alternate audio tracks reported.</p>}
              </Panel>
            ) : null}

            {menu === "subtitles" ? (
              <Panel>
                <h3><Captions size={16} /> Subtitles</h3>
                <button className="mkv-menu-item" type="button" onClick={() => setSelectedSubtitleId("off")}>
                  <span>Off</span>
                  {selectedSubtitleId === "off" ? <Check size={18} /> : null}
                </button>
                {metadata.subtitleTracks.map((track) => (
                  <button key={track.id} className="mkv-menu-item" type="button" onClick={() => setSelectedSubtitleId(track.id)}>
                    <span>{trackLabel(track)}<small>{[track.codec, track.kind, track.default ? "Default" : ""].filter(Boolean).join(" · ")}</small></span>
                    {selectedSubtitleId === track.id ? <Check size={18} /> : null}
                  </button>
                ))}
              </Panel>
            ) : null}

            {menu === "settings" ? (
              <Panel>
                <h3><Gauge size={16} /> Playback</h3>
                <label>Speed
                  <select value={state.playbackRate} onChange={(event) => { if (videoRef.current) videoRef.current.playbackRate = Number(event.target.value); }}>
                    {speeds.map((speed) => <option value={speed} key={speed}>{speed}x</option>)}
                  </select>
                </label>
                <label>Subtitle size
                  <input type="range" min={18} max={44} value={subtitleStyle.size} onChange={(event) => setSubtitleStyle((style) => ({ ...style, size: Number(event.target.value) }))} />
                </label>
                <label>Subtitle background
                  <input type="range" min={0} max={0.85} step={0.05} value={subtitleStyle.backgroundOpacity} onChange={(event) => setSubtitleStyle((style) => ({ ...style, backgroundOpacity: Number(event.target.value) }))} />
                </label>
                <label>Subtitle position
                  <input type="range" min={8} max={36} value={subtitleStyle.position} onChange={(event) => setSubtitleStyle((style) => ({ ...style, position: Number(event.target.value) }))} />
                </label>
                <label>Subtitle sync
                  <input type="number" min={-10} max={10} step={0.25} value={subtitleStyle.delay} onChange={(event) => setSubtitleStyle((style) => ({ ...style, delay: Number(event.target.value) }))} />
                </label>
                <button className="mkv-menu-item" type="button" onClick={downloadDiagnostics}>
                  <span>Export diagnostics<small>Playback events, metadata, buffer, and error state</small></span>
                  <FileDown size={18} />
                </button>
              </Panel>
            ) : null}
          </div>
        ) : null}
      </div>
      {popoutOpen && !popoutState.minimized ? (
        <>
          <button className="mkv-popout-resize mkv-popout-resize-se" type="button" aria-label="Resize from bottom right" onPointerDown={(event) => startPopoutResize(event, "se")} />
          <button className="mkv-popout-resize mkv-popout-resize-sw" type="button" aria-label="Resize from bottom left" onPointerDown={(event) => startPopoutResize(event, "sw")} />
          <button className="mkv-popout-resize mkv-popout-resize-ne" type="button" aria-label="Resize from top right" onPointerDown={(event) => startPopoutResize(event, "ne")} />
          <button className="mkv-popout-resize mkv-popout-resize-nw" type="button" aria-label="Resize from top left" onPointerDown={(event) => startPopoutResize(event, "nw")} />
        </>
      ) : null}
    </div>
    </>
  );
}
